/**
 * @file Liquid file assembler — V2.6.
 *
 * Attribute names shortened, id/data-section-id removed.
 * Uses unified ShopifyContext.buildLiquidBridge for JSON bridge generation.
 */
import type { SSGEntry } from "../types/ssg";
import { generateSchema } from "./schema";
import { getAssetRelativePath } from "./liquid-paths";
import { ATTR_HYDRATE, ATTR_COMPONENT } from "../constants/attributes";
import { buildLiquidBridge, type TrackOptions } from "../runtime/bridge";

const DISCLAIMER =
  "{% comment %}\n  IMPORTANT: This file is automatically generated by vite-plugin-shopify.\n  Do not attempt to modify this file directly, as any changes will be overwritten by the next build.\n{% endcomment %}\n";

export interface AssembleOptions {
  prefix: { template: string; section: string; block: string; snippet: string };
  outputName?: string;
  buildDir: string;
}

export function assembleLiquidFile(
  html: string,
  entry: SSGEntry,
  scriptAsset: string | null,
  cssContents: { inline: string[]; snippets: string[] },
  options: AssembleOptions,
  trackedExpressions: string[] = [],
  liquidBlocks: string[] = [],
  trackMap?: Map<string, TrackOptions>,
): string {
  const type = entry.meta.type ?? entry.targetType;
  const parts = [DISCLAIMER];

  const liquidPrepend = liquidBlocks.length > 0 ? liquidBlocks.join("\n") : "";

  switch (type) {
    case "template":
      parts.push(html);
      break;
    case "section":
      parts.push(...buildSection(html, entry, trackedExpressions, liquidPrepend, trackMap));
      break;
    case "block":
      parts.push(...buildBlock(html, entry, trackedExpressions, liquidPrepend, trackMap));
      break;
    case "snippet":
      parts.push(...buildSnippet(html, entry, trackedExpressions, liquidPrepend, trackMap));
      break;
    default:
      parts.push(...buildSection(html, entry, trackedExpressions, liquidPrepend, trackMap));
      break;
  }

  for (const snippet of cssContents.snippets) {
    parts.push("", `{% render '${snippet}' %}`);
  }

  if (cssContents.inline.length > 0) {
    parts.push(
      "",
      "{% stylesheet %}",
      ...cssContents.inline.map((c) => c.trim()),
      "{% endstylesheet %}",
    );
  }

  if (scriptAsset) {
    const assetPath = getAssetRelativePath(options.buildDir, scriptAsset);
    parts.push(
      "",
      `<script type="module" src="{{ '${assetPath}' | asset_url }}"></script>`,
    );
  }

  if (type !== "snippet") {
    parts.push(generateSchema(entry.meta));
  }

  return parts.join("\n") + "\n";
}

function resolveLiquidBridge(
  trackedExpressions: string[],
  trackMap?: Map<string, TrackOptions>,
): string {
  if (trackMap && trackMap.size > 0) {
    return buildLiquidBridge(trackMap);
  }
  // Legacy fallback: old hooks populate GW_TRACK but not GW_TRACK_MAP
  if (trackedExpressions.length > 0) {
    const entries = trackedExpressions.map((expr, i) => {
      const comma = i < trackedExpressions.length - 1 ? "," : "";
      return `    "${expr}": {{ ${expr} | json }}${comma}`;
    });
    return [
      '  <script type="application/json" data-ssg-liquid>',
      "  {",
      entries.join("\n"),
      "  }",
      "  </script>",
    ].join("\n");
  }
  return "";
}

function buildSection(
  html: string,
  entry: SSGEntry,
  trackedExpressions: string[],
  liquidPrepend: string = "",
  trackMap?: Map<string, TrackOptions>,
): string[] {
  const tag = entry.meta.tag ?? "div";
  const cls = entry.meta.class ?? "";

  const lines: string[] = [
    "",
    `<${tag}`,
  ];
  if (cls) lines.push(`  class="${cls}"`);
  lines.push(`  ${ATTR_COMPONENT}="${entry.kebabName}"`);
  lines.push(`>`);

  if (liquidPrepend) lines.push(liquidPrepend);

  const liquidBridge = resolveLiquidBridge(trackedExpressions, trackMap);
  if (liquidBridge) lines.push(liquidBridge);

  lines.push(
    `  <div ${ATTR_HYDRATE}>${html}</div>`,
  );

  // BlockSlot is now a React component rendered inside the SSR HTML.
  // No need to auto-inject a `<shopify-block-slot>` sibling — the React
  // tree declares the slot location explicitly.
  lines.push(`</${tag}>`);
  return lines;
}

function buildBlock(
  html: string,
  entry: SSGEntry,
  trackedExpressions: string[],
  liquidPrepend: string = "",
  trackMap?: Map<string, TrackOptions>,
): string[] {
  const tag = entry.meta.tag ?? "div";
  const cls = entry.meta.class ?? "";

  const lines: string[] = [
    "",
    `{%- doc -%}`,
    `  @name ${entry.meta.name}`,
    `  @context theme-block`,
    `{%- enddoc -%}`,
    "",
    `<${tag}`,
    `  id="{{ block.id }}"`,
    `  ${ATTR_COMPONENT}="${entry.kebabName}"`,
  ];
  if (cls) lines.push(`  class="${cls}"`);
  lines.push(
    `  {{ block.shopify_attributes }}`,
    `>`,
  );

  if (liquidPrepend) lines.push(liquidPrepend);

  const liquidBridge = resolveLiquidBridge(trackedExpressions, trackMap);
  if (liquidBridge) lines.push(liquidBridge);

  lines.push(
    `  <div ${ATTR_HYDRATE}>${html}</div>`,
  );

  lines.push(`</${tag}>`);
  return lines;
}

function buildSnippet(
  html: string,
  entry: SSGEntry,
  trackedExpressions: string[],
  liquidPrepend: string = "",
  trackMap?: Map<string, TrackOptions>,
): string[] {
  const lines: string[] = [
    "",
    `<div ${ATTR_COMPONENT}="${entry.kebabName}">`,
  ];

  if (liquidPrepend) lines.push(liquidPrepend);

  const liquidBridge = resolveLiquidBridge(trackedExpressions, trackMap);
  if (liquidBridge) lines.push(liquidBridge);

  lines.push(
    `  <div ${ATTR_HYDRATE}>`,
    `    ${html}`,
    `  </div>`,
    `</div>`,
  );
  return lines;
}
